let _cache: Record<string, Set<string>> | null = null;

function getDict(): Record<string, Set<string>> {
  if (_cache) return _cache;
  _cache = {};
  for (const [letter, str] of Object.entries(RAW)) {
    _cache[letter] = new Set(str.split('|'));
  }
  return _cache;
}

function norm(s: string): string {
  return s.trim().toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

export function wordExistsInDictionary(word: string): boolean {
  const n = norm(word);
  if (n.length < 2 || !n[0]) return false;
  const dict = getDict();
  return dict[n[0]]?.has(n) ?? false;
}
